int main(){int n,k;cin>>n>>k;vector<long long>dp(k+1,0);for(int i=0;i<n;i++){int w,v;cin>>w>>v;for(int j=k;j>=w;j--)dp[j]=max(dp[j],dp[j-w]+v);}cout<<dp[k]<<"\n";}
